const fields = $('Receive Lead Form').first().json.body.data.fields;
const config  = $('Get Client Config').first().json;
const rawMap  = config.field_map;
const fieldMap = typeof rawMap === 'string' ? JSON.parse(rawMap) : (rawMap || {});

function getField(label) {
  const f = fields.find(f => f.label === label);
  if (!f) return '';
  if (['MULTIPLE_CHOICE', 'DROPDOWN', 'MULTI_SELECT'].includes(f.type) && f.options) {
    const vals = Array.isArray(f.value) ? f.value : [f.value];
    return f.options
      .filter(o => vals.includes(o.id))
      .map(o => o.text)
      .join(', ');
  }
  if (Array.isArray(f.value)) return f.value.join(', ');
  return f.value ?? '';
}

const mapped = {};
for (const [label, key] of Object.entries(fieldMap)) {
  mapped[key] = getField(label);
}

const email = (mapped.email || '').toLowerCase().trim();

let state = email.split('').reduce((acc, ch) => (Math.imul(acc, 31) + ch.charCodeAt(0)) | 0, 0x811c9dc5);
let hex = '';
while (hex.length < 32) {
  state = (Math.imul(state, 1664525) + 1013904223) | 0;
  hex += (state >>> 0).toString(16).padStart(8, '0');
}
const fingerprint = hex.slice(0, 32);

return [{ json: {
  client_id:     config.client_id,
  client_slug:   config.client_slug,
  notify_email:  config.notify_email,
  sheet_id:      config.sheet_id,
  from_name:     config.from_name,
  from_email:    config.from_email,
  name:          mapped.name          || '',
  email,
  phone:         mapped.phone         || '',
  address:       mapped.address       || '',
  service:       mapped.service       || '',
  business_type: mapped.business_type || '',
  business_name: mapped.business_name || '',
  challenge:     mapped.challenge     || '',
  how_heard:     mapped.how_heard     || '',
  submitted_at:  $('Receive Lead Form').first().json.body.createdAt,
  fingerprint,
} }];

const config = $('Get Client Config').first().json;
const lead   = $('Extract and Fingerprint Lead').first().json;
return [{ json: {
  client_id:            config.client_id,
  from_name:            config.from_name,
  business_description: config.business_description || '',
  name:                 lead.name,
  service:              lead.service,
  property_type:        lead.business_type,
  message:              lead.challenge,
  business_name:        lead.business_name,
  how_heard:            lead.how_heard,
}}];

const lead = $('Extract and Fingerprint Lead').first().json;
const config = $('Get Client Config').first().json;
const scored = $('Score Lead').first().json;

const bodyHtml = (scored.email_body || '')
  .split('\n')
  .filter(line => line.trim())
  .map(line => `<p>${line}</p>`)
  .join('\n');

const baseSubject = scored.email_subject || `Thanks for reaching out, ${lead.name.split(' ')[0]}!`;

return [{ json: {
  to: lead.email,
  from: config.from_email,
  from_name: config.from_name,
  subject: `[${config.from_name}] ${baseSubject}`,
  html: bodyHtml
} }];

const lead = $('Extract and Fingerprint Lead').first().json;
const config = $('Get Client Config').first().json;
const score = $('Score Lead').first().json;

const html = `<h2>New Lead: ${lead.name}</h2><table><tr><td><b>Email:</b></td><td>${lead.email}</td></tr><tr><td><b>Phone:</b></td><td>${lead.phone || 'N/A'}</td></tr><tr><td><b>Business:</b></td><td>${lead.business_name || 'N/A'}</td></tr><tr><td><b>Type:</b></td><td>${lead.business_type || 'N/A'}</td></tr><tr><td><b>Challenge:</b></td><td>${lead.challenge || 'N/A'}</td></tr><tr><td><b>How heard:</b></td><td>${lead.how_heard || 'N/A'}</td></tr><tr><td><b>Score:</b></td><td>${score.qualification_score ?? 'N/A'}/10 — ${score.qualification_score_reason || ''}</td></tr></table>`;

const aiEmailHtml = (score.email_body || '')
  .split('\n')
  .map(line => line.trim() ? `<p style="margin:4px 0;">${line}</p>` : '')
  .join('');

const fullHtml = html + `
<br>
<table style="border-collapse:collapse;width:100%;">
  <tr><td style="background:#f0f0f0;padding:10px 14px;border-left:4px solid #aaa;">
    <p style="margin:0 0 6px 0;"><b>AI follow-up sent to client</b></p>
    <p style="margin:0 0 8px 0;color:#555;"><b>Subject:</b> ${score.email_subject || 'N/A'}</p>
    <div style="font-family:sans-serif;font-size:14px;color:#333;">${aiEmailHtml}</div>
  </td></tr>
</table>`;

return [{ json: {
  to: config.notify_email,
  from: config.from_email,
  subject: `New lead: ${lead.name} (Score: ${score.qualification_score ?? 'N/A'}/10)`,
  html: fullHtml
} }];

const body = $json.body;
const fields = body?.data?.fields || [];
const query = $json.query || {};

function getHiddenField(name) {
  const f = fields.find(f =>
    f.type === 'HIDDEN_FIELDS' &&
    typeof f.label === 'string' &&
    f.label.toLowerCase().includes('field name: ' + name.toLowerCase())
  );
  if (!f) return null;
  if (f.value !== null && f.value !== undefined && f.value !== '') return String(f.value);
  const match = f.label.match(/Default value:\s*(\S+)/);
  return match ? match[1] : null;
}

const slug = query.slug || getHiddenField('slug') || 'caiac';
const key  = query.key  || getHiddenField('key')  || '';

return [{ json: { slug, key } }];
